import numpy as np
from collections import Counter

def bleu_score(hypothesis: list[str], reference: list[str], max_n: int = 4) -> float:
    def get_ngrams(tokens, n):
        return Counter(tuple(tokens[i:i+n]) for i in range(len(tokens)-n+1))

    log_precisions = []
    for n in range(1, max_n + 1):
        hyp_ngrams = get_ngrams(hypothesis, n)
        ref_ngrams = get_ngrams(reference, n)
        clipped = sum(min(cnt, ref_ngrams[ng]) for ng, cnt in hyp_ngrams.items())
        total = max(1, len(hypothesis) - n + 1)
        p = clipped / total
        if p == 0:
            return 0.0
        log_precisions.append(np.log(p))

    bp = 1.0 if len(hypothesis) >= len(reference) else np.exp(1 - len(reference) / len(hypothesis))
    return float(bp * np.exp(np.mean(log_precisions)))
